// AGENT: Company Analysis v1.0.0 — PLACEHOLDER
// In Phase 4, this will:
//  1. Extract unique company names from deduplicated listings
//  2. Check PostgreSQL companies table cache (TTL: 72h)
//  3. For uncached companies: query Clearbit / Proxycurl / SerpAPI
//  4. Use Gemini Flash to analyze company data for red flags
//  5. Cache results in Redis + PostgreSQL

const input = $input.first().json;
const ctx   = input.execution_context;
if (!ctx) throw new Error('[company_analysis] Missing execution_context');

const started_at = Date.now();
const listings   = ctx.results.jobs_deduplicated || [];
const companies  = {};

console.log(`[company_analysis] START | unique companies to analyze`);

// Extract unique company names
const uniqueCompanies = [...new Set(listings.map(l => l.company).filter(Boolean))];

// PLACEHOLDER: Return unknown profile for each company
for (const name of uniqueCompanies) {
  companies[name] = {
    name,
    verified:          false,
    size:              'unknown',
    industry:          'unknown',
    founded_year:      null,
    website:           null,
    glassdoor_rating:  null,
    red_flags:         [],
    data_source:       'placeholder',
    last_verified_at:  new Date().toISOString()
  };
}

ctx.results.companies = companies;
ctx.agents_completed.push('company_analysis');

const duration_ms = Date.now() - started_at;
console.log(`[company_analysis] COMPLETE (placeholder) | companies=${uniqueCompanies.length}`);

return [{
  json: {
    execution_context: ctx,
    companies,
    total_analyzed: uniqueCompanies.length,
    cache_hits:     0,
    status:         'placeholder',
    agent_meta: { agent_id: 'agent-company-analysis', agent_version: '1.0.0', execution_id: ctx.execution_id, model_used: null, tokens_total: 0, duration_ms, status: 'placeholder', error: null }
  }
}];
